<template>
	<view class="detail-page">
		<view class="detail-header" :style="{ paddingTop: safeAreaInsets.top + 'px' }">
			<view class="header-left" @click="goBack">
				<text class="back-icon">‹</text>
			</view>
			<text class="header-title">订单详情</text>
			<view class="header-right"></view>
		</view>

		<view v-if="loading" class="loading-wrap"><text>加载中...</text></view>
		<view v-else-if="order" class="detail-body">
			<view class="block status-block">
				<text class="status-text">{{ statusText }}</text>
				<text class="order-no">订单号：{{ order.order_no }}</text>
			</view>
			<view class="block store-block">
				<text class="store-name">{{ order.store_name }}</text>
				<text class="order-type">{{ order.order_type === 'takeout' ? '外带' : '堂食' }}</text>
			</view>
			<view class="block items-block">
				<view class="block-title">商品明细</view>
				<view class="item-row" v-for="(it, i) in order.items" :key="i">
					<image :src="it.image || '/static/logo.png'" class="item-img" mode="aspectFill" />
					<view class="item-info">
						<text class="item-name">{{ it.name }}</text>
						<text class="item-spec" v-if="it.spec">{{ it.spec }}</text>
						<view class="item-bottom">
							<text class="item-price">¥{{ it.price }}</text>
							<text class="item-num">x{{ it.count }}</text>
						</view>
					</view>
				</view>
			</view>
			<view class="block total-block">
				<text class="total-label">实付</text>
				<text class="total-value">¥{{ order.total_amount }}</text>
			</view>
		</view>
		<view v-else class="empty-wrap"><text>订单不存在</text></view>
	</view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onLoad } from '@dcloudio/uni-app';

const { safeAreaInsets } = uni.getSystemInfoSync();

const orderId = ref('');
const order = ref(null);
const loading = ref(true);

const statusText = computed(() => {
	if (!order.value) return '';
	const map = { pending_pay: '待支付', paid: '已支付', making: '制作中', completed: '已完成', cancelled: '已取消' };
	return map[order.value.status] || order.value.status;
});

const goBack = () => {
	uni.navigateBack({ fail: () => { uni.switchTab({ url: '/pages/order/order' }); } });
};

onLoad((query) => {
	const id = query.id || '';
	orderId.value = id;
	if (id === 'local') {
		const local = uni.getStorageSync('lastOrder');
		loading.value = false;
		order.value = local || null;
		return;
	}
	const match = id.match(/^local_(\d+)$/);
	if (match) {
		const index = parseInt(match[1], 10);
		const history = uni.getStorageSync('orderHistory') || [];
		loading.value = false;
		order.value = Array.isArray(history) && history[index] ? history[index] : null;
		return;
	}
	if (!id) { loading.value = false; return; }
	uni.request({
		url: `http://localhost:3000/api/orders/${id}`,
		success: (res) => {
			loading.value = false;
			if (res.statusCode === 200 && res.data) order.value = res.data;
		},
		fail: () => { loading.value = false; },
	});
});
</script>

<style lang="scss" scoped>
@import '@/uni.scss';
.detail-page { min-height: 100vh; background: #f5f5f5; padding-bottom: 60rpx; }
.detail-header { display: flex; align-items: center; justify-content: space-between; padding: 16rpx 24rpx; background: #fff; box-shadow: 0 2rpx 8rpx rgba(0,0,0,0.04); }
.header-left { width: 80rpx; } .back-icon { font-size: 40rpx; color: #333; }
.header-title { flex: 1; text-align: center; font-size: 32rpx; font-weight: 600; color: #333; } .header-right { width: 80rpx; }
.loading-wrap, .empty-wrap { padding: 80rpx; text-align: center; color: #999; }
.block { background: #fff; margin: 20rpx 24rpx; padding: 24rpx 30rpx; border-radius: 12rpx; }
.block-title { font-size: 30rpx; font-weight: bold; color: #333; margin-bottom: 20rpx; }
.status-block .status-text { font-size: 36rpx; font-weight: bold; color: #023993; display: block; }
.status-block .order-no { font-size: 24rpx; color: #999; margin-top: 12rpx; display: block; }
.store-block { display: flex; justify-content: space-between; align-items: center; }
.store-block .store-name { font-size: 28rpx; color: #333; } .store-block .order-type { font-size: 24rpx; color: #666; }
.items-block .item-row { display: flex; padding: 20rpx 0; border-bottom: 1rpx solid #f0f0f0; }
.items-block .item-row:last-child { border-bottom: none; }
.item-img { width: 120rpx; height: 120rpx; border-radius: 8rpx; flex-shrink: 0; }
.item-info { flex: 1; margin-left: 20rpx; min-width: 0; }
.item-name { font-size: 28rpx; color: #333; display: block; } .item-spec { font-size: 24rpx; color: #999; display: block; margin-top: 6rpx; }
.item-bottom { margin-top: 12rpx; display: flex; justify-content: space-between; align-items: center; }
.item-price { font-size: 28rpx; color: #023993; font-weight: 600; } .item-num { font-size: 24rpx; color: #666; }
.total-block { display: flex; justify-content: flex-end; align-items: center; }
.total-label { font-size: 28rpx; color: #666; margin-right: 16rpx; } .total-value { font-size: 36rpx; font-weight: bold; color: #023993; }
</style>
